import { useLocation, useNavigate } from "react-router-dom";
import { useState, useMemo } from "react";
import logo from "../assets/logo.png";

export default function Checkout() {
  const location = useLocation();
  const navigate = useNavigate();

  const cart = Array.isArray(location.state?.cart) ? location.state.cart : [];

  const [form, setForm] = useState({
    name: "",
    email: "",
    address: "",
    cardType: "visa",
    cardNumber: "",
    cvv: "",
    expiry: "",
  });

  const total = useMemo(() => {
    return cart.reduce((sum, item) => {
      const price = Number(item?.price || 0);
      const qty = Number(item?.qty || 0);
      return sum + price * qty;
    }, 0);
  }, [cart]);

  const handleChange = (e) => {
    setForm((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  const handleSubmit = () => {
    console.log("COMPRA:", { customer: form, cart, total });
    alert("Compra realizada");
  };

  const inputStyle = {
    padding: "10px",
    borderRadius: "8px",
    border: "1px solid #ddd",
    outline: "none",
    width: "100%",
  };

  const primaryButton = {
    flex: 1,
    padding: "10px",
    backgroundColor: "#32d5d5",
    color: "white",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer",
  };

  const secondaryButton = {
    flex: 1,
    padding: "10px",
    backgroundColor: "#e2e8f0",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer",
  };

  const styles = {
    page: {
      minHeight: "100vh",
      background: "#f5f7fb",
      padding: "2rem",
      boxSizing: "border-box",
    },

    header: {
      textAlign: "center",
      marginBottom: "2rem",
    },

    logo: {
      width: "120px",
      marginBottom: "10px",
    },

    title: {
      margin: 0,
      fontSize: "2rem",
      color: "#0f172a",
    },

    subtitle: {
      marginTop: "0.5rem",
      color: "#64748b",
    },

    container: {
      display: "grid",
      gridTemplateColumns: "1fr 1fr",
      gap: "2rem",
      maxWidth: "1100px",
      margin: "0 auto",
    },

    column: {
      background: "white",
      borderRadius: "12px",
      padding: "1.5rem",
      boxShadow: "0 10px 30px rgba(0,0,0,0.08)",
      display: "flex",
      flexDirection: "column",
    },

    sectionTitle: {
      fontSize: "1.2rem",
      fontWeight: "700",
      color: "#0f172a",
      marginBottom: "1.5rem",
      paddingBottom: "0.5rem",
      borderBottom: "1px solid #e2e8f0",
    },

    productList: {
      display: "flex",
      flexDirection: "column",
      gap: "0.75rem",
      maxHeight: "350px",
      overflowY: "auto",
      paddingRight: "0.5rem",
    },

    productRow: {
      display: "flex",
      justifyContent: "space-between",
      fontSize: "0.9rem",
      color: "#334155",
    },

    total: {
      marginTop: "1rem",
      fontWeight: "700",
      fontSize: "1.1rem",
      color: "#0f172a",
    },

    formGroup: {
      display: "flex",
      flexDirection: "column",
      gap: "10px",
    },

    buttonRow: {
      display: "flex",
      gap: "10px",
      marginTop: "20px",
    },
  };

  if (cart.length === 0) {
    return (
      <div style={styles.page}>
        <div style={styles.header}>
          <img src={logo} style={styles.logo} />
          <h1 style={styles.title}>Checkout</h1>
          <p style={styles.subtitle}>Verifica y paga tus productos aqui.</p>
        </div>

        <div style={{ textAlign: "center" }}>
          <p>No hay productos en el carrito.</p>
          <button
            onClick={() => navigate("/tienda")}
            style={{
              padding: "10px 16px",
              background: "#32d5d5",
              color: "white",
              border: "none",
              borderRadius: "8px",
              cursor: "pointer",
            }}
          >
            Volver a la tienda
          </button>
        </div>
      </div>
    );
  }

  return (
    <div style={styles.page}>
      <div style={styles.header}>
        <img src={logo} style={styles.logo} />
        <h1 style={styles.title}>Checkout</h1>
        <p style={styles.subtitle}>Verifica y paga tus productos aqui.</p>
      </div>

      <div style={styles.container}>
        <div style={styles.column}>
          <div style={styles.sectionTitle}>Productos</div>

          <div style={styles.productList}>
            {cart.map((item, index) => (
              <div key={item.id || index} style={styles.productRow}>
                <span>
                  {item.name} x {item.qty}
                </span>
                <span>${(item.price * item.qty).toFixed(2)}</span>
              </div>
            ))}
          </div>

          <div style={styles.total}>Total: ${total.toFixed(2)}</div>
        </div>

        <div style={styles.column}>
          <div style={styles.sectionTitle}>Datos de pago</div>

          <div style={styles.formGroup}>
            <input
              name="name"
              placeholder="Nombre"
              onChange={handleChange}
              style={inputStyle}
            />
            <input
              name="email"
              placeholder="Email"
              onChange={handleChange}
              style={inputStyle}
            />
            <input
              name="address"
              placeholder="Dirección"
              onChange={handleChange}
              style={inputStyle}
            />
            <input
              name="cardNumber"
              placeholder="Número de tarjeta"
              onChange={handleChange}
              style={inputStyle}
            />
            <input
              name="cvv"
              placeholder="CVV"
              onChange={handleChange}
              style={inputStyle}
            />
            <input
              name="expiry"
              placeholder="MM/AA"
              onChange={handleChange}
              style={inputStyle}
            />
          </div>

          <div style={styles.buttonRow}>
            <button onClick={handleSubmit} style={primaryButton}>
              Confirmar
            </button>
            <button onClick={() => navigate("/tienda")} style={secondaryButton}>
              Volver
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
